//! gnosis-helix: canonical HELIX (Stoplight) corridor algebra.
//!
//! SSOT — Single Source of Truth — for the Stoplight scheduling math used by
//! every FOIL runtime in the workspace. Direct port of
//! `Gnosis.Civil.QuasicrystalStoplightTiming` (in
//! `open-source/gnosis-math/Gnosis/Civil/QuasicrystalStoplightTiming.lean`).
//!
//! All other Rust crates that need Stoplight semantics (gnosis-frf,
//! gnosis-uring, gnosis-antiqueue, distributed-inference, ...) re-export
//! the types and functions from this crate instead of maintaining a parallel
//! copy. The Aether SSOT trap (see CLAUDE.md memory) is the reason: two
//! divergent copies of the same algebra is the failure mode this crate exists
//! to eliminate.
//!
//! ## Lean correspondence (pinned in tests)
//!
//! - `Stoplight` mirrors the Lean structure: `cycle / green / offset /
//!   distance / speed`, all `Nat`-shaped (u32 in Rust).
//! - `travel_time` = Lean `travelTime`.
//! - `arrival_phase` = Lean `arrivalPhase` =
//!   `(start + travelTime + offset) % cycle`. The Lean folds `offset` INTO
//!   the arrival phase; the green window is implicitly `[0, green)` in
//!   phase space.
//! - `sees_green` = Lean `seesGreen` = `arrivalPhase start l < l.green`.
//! - `corridor_all_green` = Lean `corridorAllGreen` (every light is green).
//! - `phase_compensating_offset` = Lean `phaseCompensatingOffset`.
//! - `earliest_green_start` is the per-task version of
//!   `phaseCompensatingOffset` — the earliest tick the car's own light is
//!   green.
//!
//! Pinned Lean witnesses lifted into Rust tests:
//! - `phi_corridor_lines_up_at_zero`
//! - `phi_spacing_alone_does_not_force_alignment`
//! - `compensated_next_phi_light_is_green`
//! - `equal_step_compensated_offsets` (`[10, 20, 30, 40]`)
//! - `compensated_corridor_green_band_is_quarter_cycle` (15 of 60 ticks).
//!
//! Every kernel function is `#[inline]` because the schedulers built on top
//! call them on the hot park-loop iteration.

#![allow(clippy::module_name_repetitions)]
#![deny(unsafe_op_in_unsafe_fn)]

// ─────────────────────────────────────────────────────────────────────
// Stoplight: the fixed-time signal seen by a lonely car
// ─────────────────────────────────────────────────────────────────────

/// A fixed-time signal as seen by a lonely car. Units are discrete ticks.
///
/// Mirrors `structure Stoplight` from
/// `Gnosis.Civil.QuasicrystalStoplightTiming`. All fields `u32` so the
/// whole struct is 20 bytes (well under one cache line) and copies are
/// trivial — schedulers keep one per task and re-read it on every spin
/// iteration.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub struct Stoplight {
    /// Period of the red+green cycle, in ticks. A zero cycle is treated
    /// as "never green" by `sees_green`.
    pub cycle: u32,
    /// Duration of the green window inside one cycle, in ticks.
    pub green: u32,
    /// Phase shift — offset of the green window start within the cycle.
    pub offset: u32,
    /// Travel distance from origin to this light.
    pub distance: u32,
    /// Travel speed (distance per tick). A zero speed is treated as "no
    /// motion" (travel time = 0), matching the Lean source.
    pub speed: u32,
}

impl Stoplight {
    /// Construct a Stoplight with the conventional five fields.
    #[inline]
    pub const fn new(cycle: u32, green: u32, offset: u32, distance: u32, speed: u32) -> Self {
        Self { cycle, green, offset, distance, speed }
    }
}

// ─────────────────────────────────────────────────────────────────────
// Pure algebra: travelTime / arrivalPhase / seesGreen / corridorAllGreen
// ─────────────────────────────────────────────────────────────────────

/// Travel time = `distance / speed` (integer ticks).
///
/// Lean: `travelTime`. Zero speed degenerates to 0.
#[inline]
pub const fn travel_time(l: Stoplight) -> u32 {
    if l.speed == 0 {
        0
    } else {
        l.distance / l.speed
    }
}

/// Phase at which a car starting at `start` arrives at light `l`.
///
/// Returns `(start + travel_time(l) + l.offset) mod l.cycle`, exactly
/// matching the Lean `arrivalPhase` definition. A zero cycle is treated
/// as phase 0 (no clock to wrap against).
///
/// Uses `u64` intermediates so a Rust `u32` cannot overflow on the
/// addition before the modulus — Lean `Nat` cannot overflow but Rust
/// `u32` can.
#[inline]
pub fn arrival_phase(start: u32, l: Stoplight) -> u32 {
    if l.cycle == 0 {
        return 0;
    }
    let sum = u64::from(start) + u64::from(travel_time(l)) + u64::from(l.offset);
    (sum % u64::from(l.cycle)) as u32
}

/// True iff a car starting at `start` arrives during light `l`'s green
/// window.
///
/// Direct port of Lean `seesGreen`: `arrivalPhase start l < l.green`.
/// The Lean source folds `offset` into the arrival phase and compares
/// against the raw `green` count, so the green window effectively opens
/// at the residue `(cycle - offset) mod cycle` and runs for `green`
/// ticks. This is the predicate pinned by `phi_corridor_lines_up_at_zero`.
#[inline]
pub fn sees_green(start: u32, l: Stoplight) -> bool {
    if l.cycle == 0 {
        return false;
    }
    arrival_phase(start, l) < l.green
}

/// True iff a car starting at `start` hits every light green.
///
/// Direct port of `corridorAllGreen`. Short-circuits on the first red.
#[inline]
pub fn corridor_all_green(start: u32, lights: &[Stoplight]) -> bool {
    for &l in lights {
        if !sees_green(start, l) {
            return false;
        }
    }
    true
}

/// Count of green lights a car starting at `start` hits in the corridor.
///
/// Direct port of Lean `alignedCount`.
#[inline]
pub fn aligned_count(start: u32, lights: &[Stoplight]) -> u32 {
    let mut n: u32 = 0;
    for &l in lights {
        if sees_green(start, l) {
            n = n.saturating_add(1);
        }
    }
    n
}

/// Earliest tick `t` in `[0, light.cycle)` such that `sees_green(t, light)`
/// is true. Returns 0 if `cycle == 0` (matches the Lean fall-through).
///
/// This is the per-task version of `phase_compensating_offset` — for a
/// task carrying its own light, the earliest tick that lands it inside
/// the green window. Schedulers use it as the per-task start offset so
/// different tasks stagger their arrivals at a shared resource.
#[inline]
pub fn earliest_green_start(light: Stoplight) -> u32 {
    if light.cycle == 0 || light.green == 0 {
        return 0;
    }
    let p = arrival_phase(0, light);
    if p < light.green {
        0
    } else {
        light.cycle - p
    }
}

/// Discrete inverse: pick the `offset` so a car starting at tick 0 with
/// the given `distance` and `speed` lands at `desired_phase` on a
/// `cycle`-tick clock. Mirrors Lean `phaseCompensatingOffset`.
///
/// Closed form:
/// `(cycle + desired_phase - (distance / speed) mod cycle) mod cycle`.
///
/// Zero cycle or zero speed degenerates to 0 per the Lean fall-through.
#[inline]
pub fn phase_compensating_offset(
    cycle: u32,
    distance: u32,
    speed: u32,
    desired_phase: u32,
) -> u32 {
    if cycle == 0 {
        return 0;
    }
    let travel = if speed == 0 { 0 } else { distance / speed };
    // Stay in u64 to avoid u32 underflow on `cycle + desired_phase`.
    let lhs = u64::from(cycle) + u64::from(desired_phase);
    let rhs = u64::from(travel % cycle);
    ((lhs - rhs) % u64::from(cycle)) as u32
}

// ─────────────────────────────────────────────────────────────────────
// Tests — Lean witnesses pinned byte-for-byte
//
// Each test cites the Lean theorem name it mirrors so the cross-runtime
// parity contract is auditable from this file alone.
// ─────────────────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;

    /// Lean witness: `phi_corridor_lines_up_at_zero`. With offsets chosen
    /// to compensate each Fibonacci travel time mod 60, the lonely car
    /// hits all four green windows at start tick 0.
    #[test]
    fn phi_corridor_lines_up_at_zero() {
        let phi = [
            Stoplight::new(60, 15, 5, 55, 1),
            Stoplight::new(60, 15, 31, 89, 1),
            Stoplight::new(60, 15, 36, 144, 1),
            Stoplight::new(60, 15, 7, 233, 1),
        ];
        assert!(corridor_all_green(0, &phi));
    }

    /// Lean witness: `phi_spacing_alone_does_not_force_alignment`. A
    /// 377-distance light with zero offset is red at start tick 0.
    #[test]
    fn phi_spacing_alone_does_not_force_alignment() {
        let l = Stoplight::new(60, 15, 0, 377, 1);
        assert!(!sees_green(0, l));
    }

    /// Lean witness: `compensated_next_phi_light_is_green`. With offset
    /// 43 the 377-distance light is green at start tick 0.
    #[test]
    fn compensated_next_phi_light_is_green() {
        let l = Stoplight::new(60, 15, 43, 377, 1);
        assert!(sees_green(0, l));
    }

    /// Lean witness: `equal_step_compensated_offsets`. Pinned compensated
    /// offsets `[10, 20, 30, 40]` for distances `[50, 100, 150, 200]`.
    #[test]
    fn equal_step_compensated_offsets() {
        let expected = [10u32, 20, 30, 40];
        let distances = [50u32, 100, 150, 200];
        for (d, &want) in distances.iter().zip(&expected) {
            let got = phase_compensating_offset(60, *d, 1, 0);
            assert_eq!(got, want, "distance {d}: got {got}, want {want}");
        }
    }

    /// Lean witness: `compensated_corridor_green_band_is_quarter_cycle`.
    /// 15-tick green inside a 60-tick cycle = 15 all-green start ticks.
    #[test]
    fn compensated_corridor_green_band_is_quarter_cycle() {
        let phi = [
            Stoplight::new(60, 15, 5, 55, 1),
            Stoplight::new(60, 15, 31, 89, 1),
            Stoplight::new(60, 15, 36, 144, 1),
            Stoplight::new(60, 15, 7, 233, 1),
        ];
        let n = (0..60u32).filter(|&t| corridor_all_green(t, &phi)).count();
        assert_eq!(n, 15);
    }

    /// Lean witness: `phase_compensating_offset_hits_desired_phase_closed_witness`.
    /// `arrival_phase 0 (compensatedLightForPhase 60 15 377 1 0) = 0`.
    #[test]
    fn arrival_phase_lands_on_zero_for_compensated_377_light() {
        let cycle = 60u32;
        let distance = 377u32;
        let speed = 1u32;
        let offset = phase_compensating_offset(cycle, distance, speed, 0);
        let l = Stoplight::new(cycle, 15, offset, distance, speed);
        assert_eq!(arrival_phase(0, l), 0);
    }

    #[test]
    fn travel_time_matches_lean() {
        assert_eq!(travel_time(Stoplight::new(60, 15, 0, 377, 1)), 377);
        // speed=0 fall-through.
        assert_eq!(travel_time(Stoplight::new(60, 15, 0, 100, 0)), 0);
    }

    /// The scheduler depends on `earliest_green_start` returning a tick at
    /// which `sees_green` actually fires.
    #[test]
    fn earliest_green_start_lands_in_green_window() {
        // cycle=50, green=4, offset=17, distance=0, speed=1.
        // arrival phase = (start + 17) % 50. Green when < 4, i.e. start
        // in {33, 34, 35, 36}. earliest = 33.
        let l = Stoplight::new(50, 4, 17, 0, 1);
        let t = earliest_green_start(l);
        assert!(sees_green(t, l), "earliest_green_start returned non-green tick {t}");
        assert_eq!(t, 33);
    }

    /// `sees_green` must straddle the cycle boundary under the Lean
    /// predicate. With cycle=60, green=5, offset=58, distance=0, speed=1,
    /// arrivalPhase(start) = (start+58)%60, so green starts = {2,3,4,5,6}.
    #[test]
    fn sees_green_handles_offset_near_cycle_boundary() {
        let l = Stoplight::new(60, 5, 58, 0, 1);
        for t in [2u32, 3, 4, 5, 6] {
            assert!(sees_green(t, l), "expected green at tick {t}");
        }
        for t in [0u32, 1, 7, 30, 59] {
            assert!(!sees_green(t, l), "expected red at tick {t}");
        }
    }

    #[test]
    fn corridor_all_green_handles_empty_and_mixed() {
        assert!(corridor_all_green(0, &[]));
        let mixed = [
            Stoplight::new(10, 5, 0, 0, 1), // green at t=0..5
            Stoplight::new(10, 2, 8, 0, 1), // red at t=0
        ];
        assert!(!corridor_all_green(0, &mixed));
    }

    /// Zero-cycle fall-through: never green, never overflows.
    #[test]
    fn zero_cycle_is_never_green() {
        let l = Stoplight::new(0, 5, 0, 0, 1);
        assert!(!sees_green(0, l));
        assert!(!sees_green(u32::MAX, l));
        assert_eq!(earliest_green_start(l), 0);
        assert_eq!(arrival_phase(u32::MAX, l), 0);
    }

    /// `arrival_phase` cannot overflow u32 even at extreme inputs.
    #[test]
    fn arrival_phase_does_not_overflow_at_u32_max_inputs() {
        let l = Stoplight::new(7, 3, u32::MAX, u32::MAX, 1);
        let phase = arrival_phase(u32::MAX, l);
        assert!(phase < 7);
    }

    /// `aligned_count` matches a hand-counted sample.
    #[test]
    fn aligned_count_matches_hand_count() {
        let lights = [
            Stoplight::new(10, 5, 0, 0, 1), // green at t=0
            Stoplight::new(10, 5, 0, 0, 1), // green at t=0
            Stoplight::new(10, 2, 8, 0, 1), // red at t=0
        ];
        assert_eq!(aligned_count(0, &lights), 2);
    }
}
